INSERT INTO legacy_raw."career_content" ("id", "position", "slug", "division", "type", "link_job", "location", "description", "description_id", "requirements", "requirements_id", "status", "expiry_date", "created_at", "updated_at", "created_by", "updated_by") VALUES
  (16, ' Account Manager (Financial Services - Non Banking)', ' account-manager-financial-services-non-banking', ' Enterprise Business Directorate', ' Contract', ' https://apply.workable.com/pt-link-net-tbk-1/j/3E844F7320/apply/', ' South Jakarta City, Indonesia', ' <ul><li>Develop and execute sales strategies to capture non-banking financial services clients (<strong>Insurance Companies</strong>, <strong>Stock Exchange</strong>, <strong>Securities Companies, Investment Management Companies, etc.</strong>) establishing long-term partnerships.</li><li>Understand clients’ needs and propose appropriate LinkNet services or solution, such as internet solutions, cloud services, data center services, managed network services, IT security, etc.</li><li>Conduct sales presentations and client meetings to articulate company offerings effectively.</li><li>Manage the complete sales process from lead generation to closure, ensuring client satisfaction.</li><li>Maintain and strengthen relationships with existing clients through regular engagement.</li><li>Identify market trends and new opportunities for growth within the financial services sector.</li></ul><p><strong>Requirements</strong></p><ul><li>Candidate must possess at least a Bachelor''s Degree in finance, business, or related field.</li><li>Preferably at least 3 years of working experience in sales or account management within the non-banking financial services sector.</li><li>Strong communication, negotiation, and interpersonal skills.</li><li>Proven track record of achieving sales targets and building client relationships.</li><li>Knowledge of market dynamics in financial services is preferred.</li><li>Ability to work independently and handle pressure effectively.</li><li>Results-driven and target-oriented.</li><li>Willing to travel and visit clients as needed.</li><li>Willing to Work in <strong>Centennial Tower, South Jakarta</strong>.</li></ul><p><strong>Benefits</strong></p><ul><li>Medical Insurance</li><li>Medical Check Up</li></ul>', ' <ul><li><strong>Mengembangkan dan mengeksekusi strategi penjualan untuk menarik klien layanan keuangan non-perbankan</strong> (Perusahaan Asuransi, Bursa Efek, Perusahaan Sekuritas, Perusahaan Manajemen Investasi, dll.) serta membangun kemitraan jangka panjang.</li><li><strong>Memahami kebutuhan klien dan mengusulkan layanan atau solusi LinkNet yang sesuai</strong>, seperti solusi internet, layanan cloud, layanan pusat data, layanan jaringan terkelola, keamanan TI, dan lainnya.</li><li><strong>Melakukan presentasi penjualan dan pertemuan dengan klien</strong> untuk menjelaskan penawaran perusahaan secara efektif.</li><li><strong>Mengelola seluruh proses penjualan</strong> dari pencarian prospek hingga penutupan transaksi, dengan memastikan kepuasan klien.</li><li><strong>Memelihara dan memperkuat hubungan dengan klien yang sudah ada</strong> melalui interaksi rutin.</li><li><strong>Mengidentifikasi tren pasar dan peluang baru</strong> untuk pertumbuhan di sektor layanan keuangan.</li></ul><p><strong>Persyaratan</strong></p><ul><li>Kandidat harus memiliki setidaknya gelar Sarjana di bidang keuangan, bisnis, atau bidang terkait.</li><li>Diutamakan memiliki pengalaman kerja minimal 3 tahun dalam penjualan atau manajemen akun di sektor layanan keuangan non-perbankan.</li><li>Memiliki kemampuan komunikasi, negosiasi, dan interpersonal yang kuat.</li><li>Memiliki rekam jejak dalam mencapai target penjualan dan membangun hubungan dengan klien.</li><li>Pengetahuan tentang dinamika pasar di layanan keuangan menjadi nilai tambah.</li><li>Mampu bekerja secara mandiri dan menangani tekanan dengan efektif.</li><li>Berorientasi pada hasil dan pencapaian target.</li><li>Bersedia melakukan perjalanan dan mengunjungi klien sesuai kebutuhan.</li><li>Bersedia bekerja di <strong>Centennial Tower, Jakarta Selatan.</strong></li></ul><p><strong>Fasilitas</strong></p><ul><li>Asuransi Kesehatan</li><li>Medical Check Up</li></ul>', NULL, NULL, ' active', NULL, ' 2025-11-28 12:00:47', ' 2025-11-28 12:00:47', ' admin@gmail.com', NULL),
  (15, ' Product Manager - MSSP Security Specialist', ' product-manager-mssp-security-specialist', ' Enterprise Business Directorate', ' Full Time', ' https://apply.workable.com/pt-link-net-tbk-1/j/829D07BA18/apply/', ' South Jakarta City, Indonesia', ' <ul><li>Lead the product management processes for Managed Security Service Provider (MSSP) offerings, including strategy development, product definition, and lifecycle management.</li><li>Conduct thorough market analysis to understand customer needs, competitive landscape, and emerging trends in cybersecurity and MSSP services.</li><li>Collaborate with security, engineering, sales, and marketing teams to define product features, enhancements, and roadmap for MSSP solutions.</li><li>Create detailed product requirements and documentation, ensuring that security solutions align with client expectations and industry standards.</li><li>Engage with customers and partners for feedback and insights, driving continuous improvement of MSSP service offerings.</li><li>Analyze product performance and customer satisfaction metrics to inform strategic decisions and enhance service delivery.</li><li>Develop product positioning, messaging, and sales enablement materials to support successful product launches and marketing efforts.</li><li>Manage product budgets, pricing strategies, and profitability analysis to ensure business objectives are met.</li><li>Stay current on cybersecurity threats, technologies, and compliance requirements to inform product enhancements and updates.</li><li>Provide training and support to sales teams on the technical aspects and advantages of the MSSP offerings.</li></ul><p><strong>Requirements</strong></p><ul><li>Bachelor''s degree in Cybersecurity, Computer Science, Information Technology, or a related field; Master''s degree is a plus.</li><li>Minimum of 5 years of experience in product management with a focus on Managed Security Services.</li><li>In-depth knowledge of cybersecurity best practices, MSSP