INSERT INTO legacy_raw."news_content" ("id", "title_en", "title_id", "news_thumbnail", "slug", "excerpt_en", "excerpt_id", "author", "content_en", "content_id", "data_status", "meta_desc", "meta_keyword", "created_at", "updated_at", "news_date", "created_by", "updated_by", "id_category", "news_link", "view_count", "view_count_unique", "custom_css", "custom_js", "id_publisher") VALUES
  (1, ' Citranet Partners with Linknet to Expand Network Coverage in Yogyakarta and Banyumas', NULL, ' https://linknet.co.id/storage/files/1/news/main-image-1.jpg', ' citranet-partners-with-linknet-to-expand-network-coverage-in-yogyakarta-and-banyumas', NULL, NULL, NULL, ' <p>Linknet Corp has announced a major expansion of its network infrastructure across Indonesia, bringing high-speed internet connectivity to more remote areas of the archipelago.</p><p>This expansion includes the deployment of fiber optic cables, new data centers, and advanced networking equipment to ensure reliable and fast internet access for both residential and business customers.</p><p>The project is expected to be completed by the end of 2025 and will significantly improve digital connectivity in underserved regions.</p>', NULL, TRUE, NULL, ' linknet, network expansion, fiber optic, indonesia, internet infrastructure', ' 2025-10-03 06:37:37', ' 2026-05-27 22:23:12', ' 2025-10-02', ' admin@linknet.id', ' admin@gmail.com', 15, NULL, 2174, 1014, NULL, NULL, NULL),
  (2, ' PT Link Net Tbk Rayakan Ulang Tahun ke-25 dengan Berbagi Kebahagiaan di Bulan Ramadan', NULL, ' https://linknet.co.id/storage/files/1/news/main-image-10.jpg', ' pt-link-net-tbk-rayakan-ulang-tahun-ke-25-dengan-berbagi-kebahagiaan-di-bulan-ramadan-2', ' PT Link Net Tbk Rayakan Ulang Tahun ke-25 dengan Berbagi Kebahagiaan di Bulan Ramadan', NULL, NULL, ' <p>Linknet Corp is proud to announce the launch of our new cloud services platform specifically designed for enterprise clients seeking scalable and secure cloud solutions.</p><p>The platform features:</p><ul><li>99.9% uptime guarantee</li><li>Advanced security protocols</li><li>24/7 technical support</li><li>Flexible scaling options</li><li>Cost-effective pricing models</li></ul><p>Enterprise clients can now migrate their workloads seamlessly and take advantage of our robust cloud infrastructure.</p>', NULL, TRUE, NULL, ' cloud services, enterprise, linknet, platform, security, uptime', ' 2025-10-03 06:37:37', ' 2026-05-25 20:59:24', ' 2025-09-30', ' admin@linknet.id', ' admin@linknet.co.id', 16, NULL, 2367, 1054, NULL, NULL, NULL),
  (3, ' Centratama Group and Linknet to Enhance Broadband Connectivity Across Indonesia', NULL, ' https://linknet.co.id/storage/files/1/news/main-image-8.jpg', ' centratama-group-and-linknet-to-enhance-broadband-connectivity-across-indonesia', NULL, NULL, NULL, ' <p>According to the latest industry reports, Indonesia is leading Southeast Asia in digital transformation initiatives, with significant investments in telecommunications infrastructure and digital services.</p><p>Key highlights include:</p><ul><li>40% increase in fiber optic coverage</li><li>Growing adoption of cloud services</li><li>Government support for digital initiatives</li><li>Rising demand for high-speed internet</li></ul><p>This trend presents opportunities for telecommunications companies like Linknet Corp to expand their services and support the nation''s digital growth.</p>', NULL, TRUE, NULL, ' indonesia, digital transformation, southeast asia, telecommunications, fiber optic', ' 2025-10-03 06:37:37', ' 2026-05-27 14:47:36', ' 2025-09-28', ' admin@linknet.id', ' admin@gmail.com', 17, NULL, 1644, 753, NULL, NULL, NULL),
  (4, ' Linknet and Nexa Sign Memorandum of Understanding on ICT Network Infrastructure Cooperation', ' Linknet dan Nexa Teken Nota Kesepahaman Kerja Sama Infrastruktur Jaringan ICT', ' https://linknet.co.id/storage/files/1/news/main-image-7.jpg', ' linknet-and-nexa-sign-memorandum-of-understanding-on-ict-network-infrastructure-cooperation', ' PT Link Net Tbk (“Linknet”, Issuer Code: LINK) and PT Internet Mulia Untuk Negeri (NEXA) officially signed a Memorandum of Understanding on Strategic Cooperation in Providing Information, Communication & Technology (ICT) Infrastructure Solutions', ' PT Link Net Tbk (“Linknet”, Kode Emiten: LINK) dan PT Internet Mulia Untuk Negeri (NEXA) resmi menandatangani Nota Kesepahaman tentang Kerja Sama Strategis dalam Penyediaan Solusi Infrastruktur Information, Communication & Technology (ICT)', NULL, ' <p>Jakarta, 15 Juli 2025 — PT Link Net Tbk (“Linknet”, Kode Emiten: LINK) dan PT Internet Mulia Untuk Negeri (NEXA) resmi menandatangani Nota Kesepahaman tentang Kerja Sama Strategis dalam Penyediaan Solusi Infrastruktur Information, Communication &amp; Technology (ICT). Kolaborasi ini mencakup skema pemanfaatan serta sewa-menyewa infrastruktur jaringan milik Linknet oleh Nexa, dalam rangka mendukung perluasan layanan digital berbasis fiber optik di Indonesia.</p><p>Melalui kemitraan ini, Linknet berperan dalam menyediakan hingga menyewakan infrastruktur jaringan yang dimiliki dan dikelola kepada Nexa mencakup jaringan backbone, feeder, dan last mile berbasis teknologi Gigabit-capable Passive Optical Network (GPON). Komponen infrastruktur tersebut meliputi perangkat aktif seperti Optical Line Terminal (OLT), serta perangkat pasif seperti Optical Distribution Cabinet (ODC), Fiber Distribution Terminal (FDT), Fiber Access Terminal (FAT), dan perangkat Customer Premises Equipment (CPE) seperti Optical Network Terminal (ONT), set-top box (STB), hingga kabel instalasi ke rumah pelanggan.</p><p>CEO Linknet, Kanishka Gayan Wickrama, menyampaikan bahwa penandatanganan Nota Kesepahaman ini merupakan salah satu komitmen Linknet dalam memperluas akses konektivitas digital melalui kemitraan strategis. “Dengan memanfaatkan kekuatan infrastruktur yang telah kami bangun, kami percaya kerja sama ini akan mempercepat penetrasi layanan digital ke berbagai wilayah di Indonesia dan memberikan dampak positif bagi masyarakat luas. Inisiatif ini juga sejalan dengan visi kami, ‘We LINK the nation for better lives’,” tambah Kanishka.</p><p>CEO NEXA, Priyo Suyono, menyambut positif kolaborasi ini sebagai langkah signifikan dalam pengembangan layanan digital Nexa ke berbagai wilayah yang lebih luas. “Kemitraan ini adalah peluang besar untuk mengakselerasi ekspansi layanan kami ke berbagai kota di Indonesia. Linknet adalah mitra yang memiliki rekam jejak panjang dan kredibel dalam pembangunan infrastruktur digital. Kami percaya kolaborasi ini akan menciptakan sinergi yang kuat dan membawa manfaat signifikan bagi kedua belah pihak, serta bagi pelanggan kami di semua kota, juga kami berharap dengan hadirnya nexa di kota-kota lain bisa ikut mendorong peningkatan ekonomi digital di Indonesia” ujar Priyo.</p><p>Melalui penandatanganan Nota Kesepahaman tersebut, kedua belah pihak sepakat untuk menjalin kerja sama selama 10 (sepuluh) tahun, terhitung sejak ditandatanganinya Berita Acara Aktivasi Homepass (Ready for Service/RFS) pertama, dengan opsi perpanjangan berdasarkan kesepakatan bersama di masa mendatang.</p><p><strong>Media Contact:</strong><br>Annisa Kameila<br>Corporate Communication Specialist PT Link Net Tbk<br>M: 0878 7873 4852<br>E: annisa.kameila@linknet.co.id</p><p><strong>Tentang Linknet</strong></p><p>PT Link Net Tbk (“Linknet”, Kode Emiten: LINK), bagian dari Axiata Group, berkomitmen untuk meningkatkan kualitas hidup masyarakat dan mendukung pertumbuhan digital Indonesia melalui penyediaan infrastruktur teknologi yang cerdas dan andal. Linknet menjalankan operasionalnya melalui tiga unit bisnis utama, yaitu FiberCo untuk jaringan serat optik, EnterpriseCo untuk solusi konektivitas dan bisnis-ke-bisnis (B2B), serta MediaCo untuk layanan konten dan media. Melalui ketiga unit ini, Linknet berperan dalam mendorong kemajuan masa depan digital Indonesia.</p><p>Dengan mengusung tujuan ‘We LINK the nation for better lives’, Linknet senantiasa menempatkan pelanggan sebagai prioritas utama, mendorong inovasi dan kolaborasi, serta berkomitmen untuk terus melakukan perbaikan berkelanjutan demi menghasilkan kinerja terbaik di setiap aspek usahanya.</p><p>Saat ini, jaringan Linknet telah menjangkau berbagai wilayah strategis di Indonesia, antara lain Jabodetabek, Bandung Raya, Surabaya Raya (termasuk Malang, Gresik, dan Sidoarjo), Bali, Serang-Cilegon, Semarang, Solo, Medan, Batam, Cikampek-Purwakarta, Cirebon, Tegal, Yogyakarta, dan Kediri.</p><p><strong>Tentang Nexa</strong></p><p>PT Internet Mulia Untuk Negeri atau NEXA, adalah perusahaan Internet &amp; Digital Solutions yang memberikan pelayanan lengkap dari segala aspek. Mulai dari NEXAtel penyedia internet, IT Support, dan Infrastruktur Jaringan. NEXAapps pengembangan aplikasi dan software bisnis. NEXAdata colocation and hosting solution. NEXAdigital pengelolaan perencanaan media, broadcast email, SMS, dan Whatsapp, fotografi, videografi, identitas brand, desain grafis, dan periklanan. NEXAsolution penyedia perangkat keras, desain &amp; perencanaan ruang kontrol, dan infrastruktur data center. NEXAorganizer membuat dan melaksanakan segala ide creative event online-offline. Saat ini jaringan Nexa telah menjangkau berbagai wilayah strategis di Indonesia, antara lain Jakarta, Semarang, Yogyakarta, Solo, Salatiga, Magelang, Purwokerto, Surabaya, Bali dan Mataram.</p>', NULL, TRUE, NULL, ' linknet, award, best isp, 2024, telecommunications, indonesia', ' 2025-10-03 06:37:37', ' 2026-05-27 21:56:08', ' 2025-09-26', ' admin@linknet.id', ' admin@gmail.com', 15, NULL, 3203, 1701, NULL, NULL, NULL),
  (5, ' Enhanced Security Features Now Available for All Plans', NULL, ' https://images.unsplash.com/photo-1563013544-824ae1b704d3?w=800&h=400&fit=crop', ' enhanced-security-features-now-available-for-all-plans', NULL, NULL, NULL, ' <p>Linknet Corp has rolled out enhanced security features across all internet plans, providing our customers with advanced protection against cyber threats.</p><p>New security features include:</p><ul><li>DDoS protection for all connections</li><li>Advanced firewall configurations</li><li>Real-time threat monitoring</li><li>Automated security updates</li><li>24/7 security incident response</li></ul><p>These features are automatically enabled for all existing customers at no additional cost, demonstrating our commitment to keeping your digital activities safe and secure.</p>', NULL, TRUE, NULL, ' security features, ddos protection, firewall, linknet, cyber security, internet safety', ' 2025-10-03 06:37:37', ' 2026-05-27 23:04:32', ' 2025-09-23', ' admin@linknet.id', ' admin@linknet.id', 16, NULL, 1173, 540, NULL, NULL, NULL),
  (6, ' 5G Network Deployment Accelerates Across Indonesia', NULL, ' https://images.unsplash.com/photo-1557804506-669a67965ba0?w=800&h=400&fit=crop', ' 5g-network-deployment-accelerates-across-indonesia', NULL, NULL, NULL, ' <p>The deployment of 5G networks across Indonesia is accelerating, with major cities now experiencing significantly improved mobile connectivity and internet speeds.</p><p>Industry developments include:</p><ul><li>Major cities achieving 80% 5G coverage</li><li>Average download speeds exceeding 1 Gbps</li><li>New IoT applications emerging</li><li>Smart city initiatives gaining momentum</li></ul><p>As a leading telecommunications provider, Linknet Corp is well-positioned to support the growing demand for high-speed connectivity that complements 5G infrastructure.</p>', NULL, TRUE, NULL, ' 5g network, indonesia, telecommunications, mobile connectivity, internet speed', ' 2025-10-03 06:37:37', ' 2026-05-27 20:20:43', ' 2025-09-21', ' admin@linknet.id', ' admin@linknet.id', 17, NULL, 1792, 806, NULL, NULL, NULL),
  (10, ' Launching The High Speed Broadband Internet Up To 100mbps For Bandung Family', NULL, ' https://www.linknet.co.id/storage/files/images/media_activities/csr/LAUNCHING%20THE%20HIGH%20SPEED%20BROADBAND%20INTERNET%20UP%20TO%20100MBPS%20FOR%20BANDUNG%20FAMILY.jpg', ' launching-the-high-speed-broadband-internet-up-to-100mbps-for-bandung-family', ' Launching The High Speed Broadband Internet Up To 100mbps For Bandung Family', NULL, ' admin', ' <p><strong>Bandung, 18 Desember 2013</strong> &ndash; Dewasa ini, kebutuhan internet bagi kaum urban di Indonesia terus meningkat. Indonesia menjadi salah satu negara dengan perkembangan penggunaan internet tercepat di dunia, yaitu mencapai 63 juta di tahun 2012 dan diproyeksikan mencapai angka 83 juta pengguna internet di tahun 2013.</p>

<p>Pengguna internet di Indonesia sudah mencapai angka 74 juta* jiwa dan akan terus bertambah di kota-kota besar di Indonesia dengan prediksi peningkatan sebesar 20% setiap tahunnya hingga di tahun 2014 mendatang. Dengan fakta inilah First Media sebagai pionir TV kabel dan broadband internet hadir di Bandung.&nbsp;</p>

<p>Berbicara mengenai kehadiran First Media di Bandung setelah sebelumnya menjangkau wilayah JaBoDeTaBek, Bali, dan Surabaya, Richard Kartawijaya selaku LinkNet CEO menjelaskan, &ldquo;Hadir dan menjangkau warga Bandung di akhir tahun 2013 ini merupakan sebuah pencapaian yang baik untuk First Media. Dengan perkembangan populasi dan ekonomi Bandung yang pesat, serta kebutuhan akses internet yang terus meningkat kami merasa bahwa kehadiran First Media dengan layanan terbaru dan menarik akan mendapat apresiasi yang baik dari warga Bandung&rdquo;.</p>

<p>First Media berdiri sejak tahun 1994 di Indonesia dengan menggunakan teknologi jaringan hybrid fiber-coaxial (HFC) yang memiliki keunggulan dalam akses internet super cepat hingga 100Mbps, konten video dengan kejernihan dan ketajaman gambar berkualitas tinggi, serta layanan interaktif untuk pengguna perumahan dan perkantoran.</p>

<p>FastNet sebagai layanan internet berkecepatan tinggi memberikan pengalaman luar biasa dengan menghadirkan akses internet berkecepatan hingga 100 Mbps dengan performa yang unggul melalui kecepatan koneksi yang stabil dan minim resiko koneksi terputus sebagaimana yang biasa terjadi pada koneksi mobile dan broadband ADSL saat ini.</p>

<p>Sementara Sutrisno Budidharma selaku Director New Territory Business Development mengungkapkan bahwa seiring dengan pengembangan teknologi dan inovasi First Media, jumlah jaringan dan ketersediaan layanan First Media berkembang pesat selama tiga tahun terakhir, yaitu mencapai satu juta rumah hingga tahun 2013. Sutrisno menegaskan, &ldquo;Saat ini warga Bandung di wilayah Margahayu dan sekitarnya dapat menikmati broadband internet berkecepatan hingga 100 Mbps sehingga kegiatan mencari informasi, sosial media, bahkan bisnis online yang saat ini sedang marak pun dapat dilakukan dengan lebih lancar&rdquo;.&nbsp;</p>

<p>Berbicara mengenai rencana perluasan jaringan First Media, Sutrisno menambahkan, &ldquo;Kami berencana untuk menjangkau 100.000 rumah di Bandung hingga akhir tahun 2014. Kami berharap kesuksesan yang telah dicapai First Media selama ini, yaitu dengan mendapatkan rata-rata 40% pelanggan yang tempat tinggalnya dilalui jaringan kabel First Media dapat terealisasi juga di Bandung&rdquo;.&nbsp;</p>

<p>First Media akan terus mengembangkan teknologi dan memperluas jaringan hingga menjangkau seluruh wilayah Bandung. &ldquo;Bagi warga Bandung yang ingin mencoba kecepatan internet First Media bisa mengunjungi Butik Dukomsel di Jln. Juanda. Kami menyediakan sebuah area yang dilengkapi dengan koneksi internet broadband untuk pengunjung Dukomsel. Sementara bagi yang ingin berlangganan bisa menghubungi no telepon 022-87346565 atau mengunjungi situs First Media di www.firstmedia.com. Kami berharap akan terus mendapatkan dukungan untuk bisa memberikan akses kepada warga Bandung menuju sebuah dunia baru dalam kenyamanan menikmati gaya hidup digital&rdquo;, tutup Sutrisno.</p>', NULL, TRUE, ' Dewasa ini, kebutuhan internet bagi kaum urban di Indonesia terus meningkat. Indonesia menjadi salah satu negara dengan perkembangan penggunaan internet tercepat di dunia, yaitu mencapai 63 juta di tahun 2012 dan diproyeksikan mencapai angka 83 juta pengguna internet di tahun 2013.', ' csr, linknet, first media', ' 2021-11-29 18:17:55', ' 2026-05-27 08:35:26', ' 2013-12-18', ' admin@gmail.com', ' admin@gmail.com', 3, NULL, NULL, NULL, NULL, NULL, NULL),
  (11, ' Successful Launching Their Newest Services "Tv Anywhere" For Mobile Device', NULL, ' https://www.linknet.co.id/storage/files/images/media_activities/csr/Successful%20Launching%20Their%20Newest%20Services.jpg', ' successful-launching-their-newest-services-tv-anywhere-for-mobile-device', ' Successful Launching Their Newest Services "Tv Anywhere" For Mobile Device', NULL, ' Muhammad Daffa Prayodi', ' <p>Jakarta, 28 Februari, 2014 &ndash;First Media sebagai penyedia layanan broadband internet dan TV kabel terkemuka di Indonesia mengumumkan secara resmi kehadiran layanan terbarunya yaitu &rsquo;First Media GO&rsquo; (www.go.firstmedia.com) yang mengusung konsep &lsquo;TV Anywhere&rsquo;. &lsquo;First Media GO&rsquo; memungkinkan pelanggannya untuk dapat menikmati acara TV favoritnya dimana dan kapan saja, melalui perangkat electronic seperti computer, laptop, dan perangat mobile lainnya.</p>

<p><br />
Iris Wee selaku First Media-Linknet Chief Marketing Officer mengungkapkan, &ldquo;TV Anywhere adalah inovasi terbaru First Media yang memungkinkan pelanggan HomeCable untuk dapat menikmati layanan TV kabelnya secara online melalui perangkat mobile, baik pada saat berada di rumah maupun saat bepergian di luar rumah. Menurut data yang dilansir comScore mengenai penggunaan internet, satu dari lima pengguna internet di Indonesia menghabiskan waktu lebih dari 5 jam untuk menyaksikan video secara online. Menjawab kebutuhan tersebut, First Media dengan keunggulan internet broadband di bawah merk Fastnet menggandeng BOLT 4G LTE dengan layanan mobile broadband-nya mengembangkan teknologi streaming yang akan memberikan pengalaman luar biasa kepada para pelanggan saat menonton video secara streaming&rdquo;.</p>

<p><br />
&nbsp;&ldquo;First Media selalu berusaha untuk terus meningkatkan kualitas pelayanan dengan melakukan inovasi diberbagai hal. Layanan &lsquo;TV Anywhere&rsquo; memberikan pengalaman menonton tayangan berkualitas melalui berbagai perangkat mobile dengan fleksibilitas tinggi tanpa dikenakan biaya tambahan. Kami bangga menjadi TV berlangganan pertaman yang bisa menghadirkan kanal TV terbanyak, termasuk diataranya adalah kanal TV dengan program-program berkualitas tinggi yang sangat disukai oleh pelanggan&rdquo;, tambah Iris.</p>

<p><br />
Beberapa kanal TV favorit yang sudah tersedia antara lain : kanal berita, seperti CNN, BBC; kanal olahraga, seperti ASN dan Setanta; kanal edukasi, yaitu National Geographic dan Discovery; kanal gaya hidup, yaitu Fashion TV dan kanal Travel, serta kanal yang sangat digemari oleh anak, yaitu Nickelodeon dan Discovery Kids. First Media akan terus berupaya menggandeng berbagai penyedia konten untuk dapat menghadirkan lebih banyak kanal TV yang bisa dinikmati pelanggan. First Media juga berencana untuk menambah 10 &ndash; 20 kanal TV lainnya hingga akhir tahun nanti.&nbsp;</p>

<p><br />
Berkaitan dengan dukungan First Media terhadap giat International Java Jazz Festival ke-10, pengunjung dapat merasakan secara langsung pengalaman menikmati keunggulan &lsquo;First Media GO&rsquo; di booth First Media. &ldquo;Dengan koneksi broadband internet First Media dan kerja sama dengan BOLT 4G LTE, kami akan memfasilitasi segala kebutuhan dunia maya pelanggan, sehingga mereka dapat menikmati berbagai kanal TV favoritnya atau penampilan musisi di Java Jazz dimana saja, walaupun ketika berada ditengah kesibukan aktivitas sehari-hari&rdquo;. &nbsp;</p>

<p><br />
Untuk dapat menikmati layanan First Medi GO, pelanggan HomeCable dapat mengunjungi www.go.firstmedia.com kemudian login menggunakan First ID. &lsquo;First Media GO&rsquo; dapat diakses melalui Google Chrome atau Firefox browser untuk pengguna perangkat computer atau laptop berbasis Windows dan browser Safari untuk pengguna Mac. Sementara pengguna perangkat mobile berbasis Android dan iOS dapat terlebih dahulu mengunduk aplikasi First Media Go yang tersedia di App Store (Apple iOS) atau Play Store (Android).</p>', NULL, TRUE, ' Successful Launching Their Newest Services "Tv Anywhere" For Mobile Device', ' tv anywhere, mobile device, launching, link net', ' 2021-11-29 18:24:30', ' 2026-05-27 16:54:33', ' 2014-02-28', ' daffaprayodi@gmail.com', ' daffaprayodi@gmail.com', 3, NULL, NULL, NULL, NULL, NULL, NULL),
  (12, ' Link Net Successfully Completed IPO On The Indonesia Stock Exchange (IDX)', NULL, ' https://www.linknet.co.id/storage/files/images/media_activities/csr/linknet-ipo-listing.webp', ' link-net-successfully-completed-ipo-on-the-indonesia-stock-exchange-idx', ' Link Net Successfully Completed IPO On The Indonesia Stock Exchange (IDX)', NULL, ' Muhammad Daffa Prayodi', ' <p>Jakarta, Indonesia<br />
Jumat, 2 Juni 2014<br />
&nbsp;<br />
PT LINK NET Tbk. (&quot;Link Net&quot;), mengumumkan kesuksesan Penawaran Saham Perdana (&quot;IPO&quot;) pada hari ini di Bursa Efek Indonesia di Jakarta.</p>

<p>IPO terdiri dari 304.265.000 (tiga ratus empat juta dua ratus enam puluh lima ribu) saham biasa Link Net yang dimiliki oleh Pemegang Saham Penjual, dengan nilai nominal Rp100 saham. Penawaran ini mewakili 10 % (sepuluh persen) modal disetor Perseroan. Saham ditawarkan dengan harga penawaran Rp 1.600 per saham dan sekarang tersedia untuk diperdagangkan di Bursa Efek Indonesia di bawah simbol &quot;LINK&quot;.<br />
&nbsp;<br />
PT Ciptadana Securities telah ditunjuk sebagai Penjamin Emisi Efek untuk IPO.<br />
&nbsp;<br />
Roberto Feliciano, Presiden Direktur Link Net menyatakan &quot;Kami sangat senang telah berhasil menyelesaikan IPO Perseroan. Kami berkomitmen untuk mengembangkan infrastruktur informasi berbasis untuk membawa Indonesia menjadi masyarakat yang cerdas. Permintaan dan kebutuhan untuk produk internet dan jasa TV berbayar seiring dengan perkembangan teknologi masih kurang terpenuhi di Indonesia. Pencatatan saham Perseroan meningkatkan profil dari Link Net dan membuat Perseroan lebih dihargai oleh pasar dan untuk memberikan transparansi yang lebih bagi investor. Saya ingin mengucapkan terima kasih kepada investor kami yang telah menempatkan kepercayaan dalam Perseroan dan manajemen kami.&quot;</p>

<p>Sekilas PT Link Net Tbk.<br />
PT Link Net Tbk. (&ldquo;Link Net&rdquo;), didirikan pada tahun 1996, adalah penyedia terbesar layanan melalui kabel di Indonesia, menyediakan layanan televisi berlangganan, Internet Pita Lebar (Broadband) dan komunikasi data. Link Net beroperasi di Jabodetabek, yang memiliki populasi dasar lima juta rumah tangga dengan enam ratus enam puluh ribu pelanggan internet dan TV kabel. Link Net memiliki dan mengoperasikan jaringan kabel Hybrid Fiber Coaxial (&ldquo;HFC&rdquo;) digital dua-arah yang luas yang menyediakan layanan akses internet berkecepatan tinggi untuk pelanggan ritel dan bisnis, termasuk menyediakan berbagai layanan komunikasi data melalui jaringan serat optik perseroan. Link Net juga mengoperasikan saluran televisi berlangganan bekerja sama dengan PT First Media Television yang menyediakan saluran televisi lokal dan internasional.</p>

<p>Untuk informasi lebih lanjut silahkan hubungi :<br />
Sekretaris Perusahaan PT Link Net Tbk :<br />
Dicky Moechtar, Direktur<br />
Telepon : ( 021 ) &ndash; 5278811<br />
Fax : ( 021 ) &ndash; 5278833<br />
Email : corporate.secretary@linknet.co.id</p>', NULL, TRUE, ' Link Net Successfully Completed IPO On The Indonesia Stock Exchange (IDX)', ' IPO, Link Net, Indonesia Stock Exchange, IDX', ' 2021-11-29 18:27:55', ' 2026-05-27 18:03:09', ' 2014-06-02', ' daffaprayodi@gmail.com', ' daffaprayodi@gmail.com', 3, NULL, NULL, NULL, NULL, NULL, NULL),
  (13, ' Link Net Reports Strong Results In 2014, With A 54.0% Increase In Net Income', NULL, ' https://www.linknet.co.id/storage/files/images/media_activities/linknet-default-old.png', ' link-net-reports-strong-results-in-2014-with-a-54-0-increase-in-net-income', ' Link Net Reports Strong Results In 2014, With A 54.0% Increase In Net Income', NULL, ' Muhammad Daffa Prayodi', ' <p><strong>FY 2014 Highlights: </strong></p>

<ul>
	<li><strong>Total revenue up 28.3% to Rp 2,136.0 billion </strong></li>
	<li><strong>Adjusted EBITDA margin up 3.5 percentage points to 57.6% </strong></li>
	<li><strong>1.4 million homes passed achieved with 238,161 additional homes passed in 2014 </strong></li>
	<li><strong>Broadband RGUs reached 392,134 and Cable TV*) RGUs reached 362,643, representing growth of 17.8% and 19.2%, respectively </strong></li>
</ul>

<p>PT Link Net Tbk (&ldquo;Link Net&rdquo; or &ldquo;the Company&rdquo;; stock code: &ldquo;LINK&rdquo;) reported strong full year 2014 results for the year ended 31 December 2014, with a record net income of Rp 557.9 billion, a significant increase of 54.0% compared to FY2013.</p>

<p>Total revenue was Rp 2,136.0 billion, a 28.3% increase over last year. This reflects the Company&rsquo;s continued commitment to network expansion and meeting the demand for broadband and cable TV*) services.</p>

<p>With prudent cost management and relying on operating leverage, adjusted EBITDA also increased by 36.6% to Rp 1,230.7 billion for FY2014. This is on the back of a total of approximately 755 thousand RGUs (&ldquo;Revenue Generating Units&rdquo;) consisting of both broadband and cable TV services.</p>

